/**
 * Integration tests for the analytics pipeline.
 *
 * Tests the full flow: AnalyticsRoutes → AnalyticsService → Repositories → Database.
 * Uses real instances (no mocks) with seeded test data.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { AnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/analytics.routes.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type { DashboardData, MetricSummary, TimeSeriesData, OrderStatusBreakdown, TopEntity } from '../../src/models/analytics.js';

// ── Test data helpers ──

function makeUser(overrides: Partial<User> & { id: string; name: string; email: string }): User {
  return {
    role: 'member',
    createdAt: new Date('2026-01-05T10:00:00Z'),
    updatedAt: new Date('2026-01-05T10:00:00Z'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> & { id: string; userId: string; total: number }): Order {
  return {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: overrides.total }],
    status: 'delivered',
    createdAt: new Date('2026-01-15T12:00:00Z'),
    updatedAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

function makeReq(params: Record<string, string> = {}, query: Record<string, string> = {}): RouteRequest {
  return { params, query };
}

describe('Analytics Pipeline Integration', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;
  let routes: AnalyticsRoutes;

  // Seed users and orders for a realistic scenario
  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = new AnalyticsRoutes(service);

    // Seed 3 users
    userRepo.save(makeUser({ id: 'u1', name: 'Alice', email: 'alice@test.com', createdAt: new Date('2026-01-02T00:00:00Z'), updatedAt: new Date('2026-01-02T00:00:00Z') }));
    userRepo.save(makeUser({ id: 'u2', name: 'Bob', email: 'bob@test.com', createdAt: new Date('2026-01-10T00:00:00Z'), updatedAt: new Date('2026-01-10T00:00:00Z') }));
    userRepo.save(makeUser({ id: 'u3', name: 'Carol', email: 'carol@test.com', createdAt: new Date('2026-02-01T00:00:00Z'), updatedAt: new Date('2026-02-01T00:00:00Z') }));

    // Seed orders across January 2026
    orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, status: 'delivered', createdAt: new Date('2026-01-05T10:00:00Z'), updatedAt: new Date('2026-01-05T10:00:00Z') }));
    orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200, status: 'delivered', createdAt: new Date('2026-01-10T10:00:00Z'), updatedAt: new Date('2026-01-10T10:00:00Z') }));
    orderRepo.save(makeOrder({ id: 'o3', userId: 'u2', total: 150, status: 'shipped', createdAt: new Date('2026-01-15T10:00:00Z'), updatedAt: new Date('2026-01-15T10:00:00Z') }));
    orderRepo.save(makeOrder({ id: 'o4', userId: 'u2', total: 50, status: 'pending', createdAt: new Date('2026-01-20T10:00:00Z'), updatedAt: new Date('2026-01-20T10:00:00Z') }));
    orderRepo.save(makeOrder({ id: 'o5', userId: 'u1', total: 300, status: 'cancelled', createdAt: new Date('2026-01-25T10:00:00Z'), updatedAt: new Date('2026-01-25T10:00:00Z') }));
  });

  // ── Dashboard endpoint ──

  describe('GET /api/analytics/dashboard', () => {
    it('returns full dashboard with all widgets populated', () => {
      const res = routes.getDashboard(makeReq({}, {
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-02-01T00:00:00Z',
      }));

      expect(res.status).toBe(200);
      const data = res.body as DashboardData;

      // 4 metric summaries
      expect(data.metrics).toHaveLength(4);
      expect(data.metrics.map(m => m.metric)).toEqual([
        'revenue', 'orders', 'users', 'average-order-value',
      ]);

      // Revenue should be sum of all orders in range
      const revenueSummary = data.metrics.find(m => m.metric === 'revenue')!;
      expect(revenueSummary.currentValue).toBe(800); // 100+200+150+50+300

      // Orders count
      const ordersSummary = data.metrics.find(m => m.metric === 'orders')!;
      expect(ordersSummary.currentValue).toBe(5);

      // Time series present
      expect(data.revenueTimeSeries.metric).toBe('revenue');
      expect(data.revenueTimeSeries.points.length).toBeGreaterThan(0);
      expect(data.ordersTimeSeries.metric).toBe('orders');

      // Order status breakdown covers all 5 statuses
      expect(data.ordersByStatus).toHaveLength(5);

      // Top customers present
      expect(data.topCustomers.length).toBeGreaterThan(0);

      // Timestamp present
      expect(data.generatedAt).toBeTruthy();
    });

    it('filters by userId when provided', () => {
      const res = routes.getDashboard(makeReq({}, {
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-02-01T00:00:00Z',
        userId: 'u1',
      }));

      expect(res.status).toBe(200);
      const data = res.body as DashboardData;

      // Only u1's orders: 100+200+300 = 600
      const revenueSummary = data.metrics.find(m => m.metric === 'revenue')!;
      expect(revenueSummary.currentValue).toBe(600);

      const ordersSummary = data.metrics.find(m => m.metric === 'orders')!;
      expect(ordersSummary.currentValue).toBe(3);
    });

    it('supports granularity parameter', () => {
      const res = routes.getDashboard(makeReq({}, {
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-02-01T00:00:00Z',
        granularity: 'week',
      }));

      expect(res.status).toBe(200);
      const data = res.body as DashboardData;
      expect(data.revenueTimeSeries.granularity).toBe('week');
      // ~4-5 weekly buckets for January
      expect(data.revenueTimeSeries.points.length).toBeGreaterThanOrEqual(4);
      expect(data.revenueTimeSeries.points.length).toBeLessThanOrEqual(5);
    });

    it('returns 400 when startDate is missing', () => {
      const res = routes.getDashboard(makeReq({}, { endDate: '2026-02-01T00:00:00Z' }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('startDate');
    });

    it('returns 400 when endDate is missing', () => {
      const res = routes.getDashboard(makeReq({}, { startDate: '2026-01-01T00:00:00Z' }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('endDate');
    });

    it('returns 400 when startDate is not a valid date', () => {
      const res = routes.getDashboard(makeReq({}, {
        startDate: 'not-a-date',
        endDate: '2026-02-01T00:00:00Z',
      }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('startDate');
    });

    it('returns 400 when startDate >= endDate', () => {
      const res = routes.getDashboard(makeReq({}, {
        startDate: '2026-02-01T00:00:00Z',
        endDate: '2026-01-01T00:00:00Z',
      }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('before');
    });

    it('returns 400 for invalid granularity', () => {
      const res = routes.getDashboard(makeReq({}, {
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-02-01T00:00:00Z',
        granularity: 'quarter',
      }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('granularity');
    });
  });

  // ── Metric summary endpoint ──

  describe('GET /api/analytics/metrics/:type', () => {
    it('returns revenue metric with correct values', () => {
      const res = routes.getMetricSummary(makeReq(
        { type: 'revenue' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.metric).toBe('revenue');
      expect(data.currentValue).toBe(800);
      // Previous period (Dec 2025) has no orders, so previousValue = 0
      expect(data.previousValue).toBe(0);
      expect(data.changePercent).toBe(100); // from 0 to non-zero = 100%
    });

    it('returns orders metric with correct count', () => {
      const res = routes.getMetricSummary(makeReq(
        { type: 'orders' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.metric).toBe('orders');
      expect(data.currentValue).toBe(5);
    });

    it('returns users metric counting new users in range', () => {
      const res = routes.getMetricSummary(makeReq(
        { type: 'users' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.metric).toBe('users');
      // u1 (Jan 2), u2 (Jan 10) created in Jan; u3 is Feb 1 (exclusive end)
      expect(data.currentValue).toBe(2);
    });

    it('returns average-order-value metric', () => {
      const res = routes.getMetricSummary(makeReq(
        { type: 'average-order-value' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.metric).toBe('average-order-value');
      expect(data.currentValue).toBe(160); // 800 / 5
    });

    it('returns 400 for invalid metric type', () => {
      const res = routes.getMetricSummary(makeReq(
        { type: 'invalid-metric' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('Invalid metric type');
    });

    it('returns 400 when metric type is missing', () => {
      const res = routes.getMetricSummary(makeReq(
        {},
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('metric type');
    });

    it('returns 400 when date range is missing', () => {
      const res = routes.getMetricSummary(makeReq({ type: 'revenue' }, {}));
      expect(res.status).toBe(400);
    });
  });

  // ── Time series endpoint ──

  describe('GET /api/analytics/time-series/:type', () => {
    it('returns daily time series with data points', () => {
      const res = routes.getTimeSeries(makeReq(
        { type: 'revenue' },
        {
          startDate: '2026-01-01T00:00:00Z',
          endDate: '2026-02-01T00:00:00Z',
          granularity: 'day',
        },
      ));

      expect(res.status).toBe(200);
      const data = res.body as TimeSeriesData;
      expect(data.metric).toBe('revenue');
      expect(data.granularity).toBe('day');
      expect(data.start).toBe('2026-01-01T00:00:00Z');
      expect(data.end).toBe('2026-02-01T00:00:00Z');
      // 31 days in January
      expect(data.points).toHaveLength(31);

      // Verify that total across all points equals total revenue
      const totalRevenue = data.points.reduce((sum, p) => sum + p.value, 0);
      expect(totalRevenue).toBe(800);
    });

    it('returns weekly time series', () => {
      const res = routes.getTimeSeries(makeReq(
        { type: 'orders' },
        {
          startDate: '2026-01-01T00:00:00Z',
          endDate: '2026-02-01T00:00:00Z',
          granularity: 'week',
        },
      ));

      expect(res.status).toBe(200);
      const data = res.body as TimeSeriesData;
      expect(data.granularity).toBe('week');
      // Total orders across all buckets should be 5
      const totalOrders = data.points.reduce((sum, p) => sum + p.value, 0);
      expect(totalOrders).toBe(5);
    });

    it('returns hourly time series for a single day', () => {
      const res = routes.getTimeSeries(makeReq(
        { type: 'revenue' },
        {
          startDate: '2026-01-05T00:00:00Z',
          endDate: '2026-01-06T00:00:00Z',
          granularity: 'hour',
        },
      ));

      expect(res.status).toBe(200);
      const data = res.body as TimeSeriesData;
      expect(data.granularity).toBe('hour');
      expect(data.points).toHaveLength(24);
      // Order o1 was at 10:00, so hour bucket 10 should have value 100
      const totalRevenue = data.points.reduce((sum, p) => sum + p.value, 0);
      expect(totalRevenue).toBe(100);
    });

    it('returns 400 for invalid metric type', () => {
      const res = routes.getTimeSeries(makeReq(
        { type: 'bogus' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));
      expect(res.status).toBe(400);
    });

    it('returns 400 for invalid granularity', () => {
      const res = routes.getTimeSeries(makeReq(
        { type: 'revenue' },
        {
          startDate: '2026-01-01T00:00:00Z',
          endDate: '2026-02-01T00:00:00Z',
          granularity: 'yearly',
        },
      ));
      expect(res.status).toBe(400);
    });
  });

  // ── Orders by status endpoint ──

  describe('GET /api/analytics/orders/status', () => {
    it('returns breakdown of all orders by status', () => {
      const res = routes.getOrdersByStatus(makeReq());

      expect(res.status).toBe(200);
      const data = res.body as OrderStatusBreakdown[];
      expect(data).toHaveLength(5);

      const delivered = data.find(d => d.status === 'delivered')!;
      expect(delivered.count).toBe(2); // o1, o2
      expect(delivered.total).toBe(300); // 100 + 200

      const shipped = data.find(d => d.status === 'shipped')!;
      expect(shipped.count).toBe(1);
      expect(shipped.total).toBe(150);

      const pending = data.find(d => d.status === 'pending')!;
      expect(pending.count).toBe(1);
      expect(pending.total).toBe(50);

      const cancelled = data.find(d => d.status === 'cancelled')!;
      expect(cancelled.count).toBe(1);
      expect(cancelled.total).toBe(300);

      const confirmed = data.find(d => d.status === 'confirmed')!;
      expect(confirmed.count).toBe(0);
      expect(confirmed.total).toBe(0);
    });
  });

  // ── Top customers endpoint ──

  describe('GET /api/analytics/top-customers', () => {
    it('returns top customers ranked by total revenue', () => {
      const res = routes.getTopCustomers(makeReq({}, {}));

      expect(res.status).toBe(200);
      const data = res.body as TopEntity[];
      expect(data).toHaveLength(2); // u1 and u2

      // u1: 100+200+300=600, u2: 150+50=200
      expect(data[0].id).toBe('u1');
      expect(data[0].name).toBe('Alice');
      expect(data[0].value).toBe(600);

      expect(data[1].id).toBe('u2');
      expect(data[1].name).toBe('Bob');
      expect(data[1].value).toBe(200);
    });

    it('respects limit parameter', () => {
      const res = routes.getTopCustomers(makeReq({}, { limit: '1' }));

      expect(res.status).toBe(200);
      const data = res.body as TopEntity[];
      expect(data).toHaveLength(1);
      expect(data[0].id).toBe('u1');
    });

    it('returns 400 for non-integer limit', () => {
      const res = routes.getTopCustomers(makeReq({}, { limit: '2.5' }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('limit');
    });

    it('returns 400 for zero limit', () => {
      const res = routes.getTopCustomers(makeReq({}, { limit: '0' }));
      expect(res.status).toBe(400);
    });

    it('returns 400 for negative limit', () => {
      const res = routes.getTopCustomers(makeReq({}, { limit: '-1' }));
      expect(res.status).toBe(400);
    });
  });

  // ── Time-range filtering ──

  describe('Time-range filtering', () => {
    it('narrows results to the specified date range', () => {
      // Only first half of January: should get o1 (Jan 5) and o2 (Jan 10)
      const res = routes.getMetricSummary(makeReq(
        { type: 'revenue' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-01-12T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.currentValue).toBe(300); // 100 + 200
    });

    it('excludes orders outside the range', () => {
      // Only Jan 20-31: should get o4 (Jan 20) and o5 (Jan 25)
      const res = routes.getMetricSummary(makeReq(
        { type: 'revenue' },
        { startDate: '2026-01-18T00:00:00Z', endDate: '2026-01-31T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.currentValue).toBe(350); // 50 + 300
    });

    it('returns zero for a range with no data', () => {
      const res = routes.getMetricSummary(makeReq(
        { type: 'revenue' },
        { startDate: '2026-03-01T00:00:00Z', endDate: '2026-04-01T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.currentValue).toBe(0);
    });
  });

  // ── Empty data scenarios ──

  describe('Empty data scenarios', () => {
    let emptyRoutes: AnalyticsRoutes;

    beforeEach(() => {
      const emptyDb = new Database();
      const emptyUserRepo = new UserRepository(emptyDb);
      const emptyOrderRepo = new OrderRepository(emptyDb);
      const emptyService = new AnalyticsService(emptyOrderRepo, emptyUserRepo);
      emptyRoutes = new AnalyticsRoutes(emptyService);
    });

    it('dashboard returns zeros with no data', () => {
      const res = emptyRoutes.getDashboard(makeReq({}, {
        startDate: '2026-01-01T00:00:00Z',
        endDate: '2026-02-01T00:00:00Z',
      }));

      expect(res.status).toBe(200);
      const data = res.body as DashboardData;

      for (const metric of data.metrics) {
        expect(metric.currentValue).toBe(0);
        expect(metric.previousValue).toBe(0);
      }
      expect(data.topCustomers).toEqual([]);
      for (const status of data.ordersByStatus) {
        expect(status.count).toBe(0);
        expect(status.total).toBe(0);
      }
    });

    it('time series returns zero-valued points with no data', () => {
      const res = emptyRoutes.getTimeSeries(makeReq(
        { type: 'revenue' },
        {
          startDate: '2026-01-01T00:00:00Z',
          endDate: '2026-01-08T00:00:00Z',
          granularity: 'day',
        },
      ));

      expect(res.status).toBe(200);
      const data = res.body as TimeSeriesData;
      expect(data.points).toHaveLength(7);
      for (const point of data.points) {
        expect(point.value).toBe(0);
      }
    });

    it('orders by status returns all statuses with zero counts', () => {
      const res = emptyRoutes.getOrdersByStatus(makeReq());

      expect(res.status).toBe(200);
      const data = res.body as OrderStatusBreakdown[];
      expect(data).toHaveLength(5);
      for (const entry of data) {
        expect(entry.count).toBe(0);
        expect(entry.total).toBe(0);
      }
    });
  });

  // ── Previous period comparison ──

  describe('Previous period comparison', () => {
    it('computes change percentage correctly when previous period has data', () => {
      // Add an order in December 2025 (the previous period for Jan query)
      orderRepo.save(makeOrder({
        id: 'o-dec',
        userId: 'u1',
        total: 400,
        createdAt: new Date('2025-12-15T10:00:00Z'),
        updatedAt: new Date('2025-12-15T10:00:00Z'),
      }));

      const res = routes.getMetricSummary(makeReq(
        { type: 'revenue' },
        { startDate: '2026-01-01T00:00:00Z', endDate: '2026-02-01T00:00:00Z' },
      ));

      expect(res.status).toBe(200);
      const data = res.body as MetricSummary;
      expect(data.currentValue).toBe(800);
      expect(data.previousValue).toBe(400);
      expect(data.changePercent).toBe(100); // (800-400)/400 * 100 = 100%
    });
  });
});

